    async def workflows_business_hours_destroy(
        self, workflow_pk: int, id: int, *, request_options: typing.Optional[RequestOptions] = None
    ) -> None:
        """
        CRUD for BusinessHoursConfig nested under a workflow (OneToOne).

        Since a workflow has at most one business hours config, this behaves as
        a singleton resource under the workflow:

            GET    /workflows/{workflow_pk}/business-hours/      — list (0 or 1)
            POST   /workflows/{workflow_pk}/business-hours/      — create
            GET    /workflows/{workflow_pk}/business-hours/{pk}/  — retrieve
            PUT    /workflows/{workflow_pk}/business-hours/{pk}/  — full update
            PATCH  /workflows/{workflow_pk}/business-hours/{pk}/  — partial update
            DELETE /workflows/{workflow_pk}/business-hours/{pk}/  — delete

        Parameters
        ----------
        workflow_pk : int

        id : int
            A unique integer value identifying this Business Hours Config.

        request_options : typing.Optional[RequestOptions]
            Request-specific configuration.

        Returns
        -------
        None

        Examples
        --------
        import asyncio

        from zenlabs_sdk import AsyncZenClient

        client = AsyncZenClient(
            tenant_id="YOUR_TENANT_ID",
            token="YOUR_TOKEN",
        )


        async def main() -> None:
            await client.workflow.workflows_business_hours_destroy(
                workflow_pk=1,
                id=1,
            )


        asyncio.run(main())
        """
        _response = await self._raw_client.workflows_business_hours_destroy(
            workflow_pk, id, request_options=request_options
        )
        return _response.data

